function loadQuestions(lang) {
  var normalizedLang = lang === "it" ? "it" : "en";

  return (window.QUIZ_DATA || []).map(function(question) {
    var localizedQuestionText = normalizedLang === "it"
      ? (question.text_it || question.text)
      : question.text;

    var localizedExplanation = normalizedLang === "it"
      ? (question.explanation_it || question.explanation || "")
      : (question.explanation || "");

    var localizedOptions = (question.options || []).map(function(option) {
      return {
        id: option.id,
        text: normalizedLang === "it" ? (option.text_it || option.text) : option.text,
        correct: Boolean(option.correct)
      };
    });

    return {
      id: question.id,
      objective: question.objective,
      text: localizedQuestionText,
      options: localizedOptions,
      explanation: localizedExplanation
    };
  });
}
